          'c72214909f993883807c2feca403d2201165c438 1 1 46\nauthor Diego Alvarez\nauthor-mail <diego.alvarez@example.com>\nauthor-time 1777301100\nauthor-tz +0200\ncommitter Diego Alvarez\ncommitter-mail <diego.alvarez@example.com>\ncommitter-time 1777301100\ncommitter-tz +0200\nsummary feat(tree): add min-heap Huffman tree builder and code-length derivation\nfilename tree.py\n\timport heapq\nc72214909f993883807c2feca403d2201165c438 2 2\n\tfrom dataclasses import dataclass, field\nc72214909f993883807c2feca403d2201165c438 3 3\n\t\nc72214909f993883807c2feca403d2201165c438 4 4\n\t\nc72214909f993883807c2feca403d2201165c438 5 5\n\t@dataclass(order=True)\nc72214909f993883807c2feca403d2201165c438 6 6\n\tclass _Node:\nc72214909f993883807c2feca403d2201165c438 7 7\n\t    freq: int\nc72214909f993883807c2feca403d2201165c438 8 8\n\t    symbol: int | None = field(compare=False, default=None)\nc72214909f993883807c2feca403d2201165c438 9 9\n\t    left: "_Node | None" = field(compare=False, default=None)\nc72214909f993883807c2feca403d2201165c438 10 10\n\t    right: "_Node | None" = field(compare=False, default=None)\nc72214909f993883807c2feca403d2201165c438 11 11\n\t\nc72214909f993883807c2feca403d2201165c438 12 12\n\t\nc72214909f993883807c2feca403d2201165c438 13 13\n\tdef build_code_lengths(freq_table: list[tuple[int, int]]) -> dict[int, int]:\nc72214909f993883807c2feca403d2201165c438 14 14\n\t    """Build canonical Huffman code-length table from a frequency table.\nc72214909f993883807c2feca403d2201165c438 15 15\n\t\nc72214909f993883807c2feca403d2201165c438 16 16\n\t    Returns a mapping of symbol -> bit length. An empty freq_table returns {}.\nc72214909f993883807c2feca403d2201165c438 17 17\n\t    A single-symbol freq_table assigns length 1 to that symbol.\nc72214909f993883807c2feca403d2201165c438 18 18\n\t    """\nc72214909f993883807c2feca403d2201165c438 19 19\n\t    if not freq_table:\nc72214909f993883807c2feca403d2201165c438 20 20\n\t        return {}\nc72214909f993883807c2feca403d2201165c438 21 21\n\t\nc72214909f993883807c2feca403d2201165c438 22 22\n\t    heap: list[_Node] = [_Node(freq, sym) for sym, freq in freq_table]\nc72214909f993883807c2feca403d2201165c438 23 23\n\t    heapq.heapify(heap)\nc72214909f993883807c2feca403d2201165c438 24 24\n\t\nc72214909f993883807c2feca403d2201165c438 25 25\n\t    if len(heap) == 1:\nc72214909f993883807c2feca403d2201165c438 26 26\n\t        return {heap[0].symbol: 1}\nc72214909f993883807c2feca403d2201165c438 27 27\n\t\nc72214909f993883807c2feca403d2201165c438 28 28\n\t    while len(heap) > 1:\nc72214909f993883807c2feca403d2201165c438 29 29\n\t        a = heapq.heappop(heap)\nc72214909f993883807c2feca403d2201165c438 30 30\n\t        b = heapq.heappop(heap)\nc72214909f993883807c2feca403d2201165c438 31 31\n\t        heapq.heappush(heap, _Node(a.freq + b.freq, left=a, right=b))\nc72214909f993883807c2feca403d2201165c438 32 32\n\t\nc72214909f993883807c2feca403d2201165c438 33 33\n\t    root = heap[0]\nc72214909f993883807c2feca403d2201165c438 34 34\n\t    lengths: dict[int, int] = {}\nc72214909f993883807c2feca403d2201165c438 35 35\n\t\nc72214909f993883807c2feca403d2201165c438 36 36\n\t    def _walk(node: _Node, depth: int) -> None:\nc72214909f993883807c2feca403d2201165c438 37 37\n\t        if node.symbol is not None:\nc72214909f993883807c2feca403d2201165c438 38 38\n\t            lengths[node.symbol] = depth\nc72214909f993883807c2feca403d2201165c438 39 39\n\t        else:\nc72214909f993883807c2feca403d2201165c438 40 40\n\t            if node.left:\nc72214909f993883807c2feca403d2201165c438 41 41\n\t                _walk(node.left, depth + 1)\nc72214909f993883807c2feca403d2201165c438 42 42\n\t            if node.right:\nc72214909f993883807c2feca403d2201165c438 43 43\n\t                _walk(node.right, depth + 1)\nc72214909f993883807c2feca403d2201165c438 44 44\n\t\nc72214909f993883807c2feca403d2201165c438 45 45\n\t    _walk(root, 0)\nc72214909f993883807c2feca403d2201165c438 46 46\n\t    return lengths\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 47 47 25\nauthor Priya Natarajan\nauthor-mail <priya.natarajan@example.com>\nauthor-time 1778058600\nauthor-tz +0200\ncommitter Priya Natarajan\ncommitter-mail <priya.natarajan@example.com>\ncommitter-time 1778058600\ncommitter-tz +0200\nsummary feat(tree): add canonical-code generator from code-length table\nprevious 11be3ed3671e4ebcc72d579b0b7c2329224c2d0b tree.py\nfilename tree.py\n\t\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 48 48\n\t\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 49 49\n\tdef build_canonical_codes(lengths: dict[int, int]) -> dict[int, tuple[int, int]]:\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 50 50\n\t    """Derive canonical bit codes from a code-length table.\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 51 51\n\t\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 52 52\n\t    Returns {symbol: (code_int, bit_length)}.  Canonical assignment:\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 53 53\n\t    sort symbols by (length, symbol), assign codes starting at 0 and\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 54 54\n\t    left-shifting + incrementing at each length boundary.\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 55 55\n\t    """\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 56 56\n\t    if not lengths:\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 57 57\n\t        return {}\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 58 58\n\t\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 59 59\n\t    sorted_syms = sorted(lengths, key=lambda s: (lengths[s], s))\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 60 60\n\t    codes: dict[int, tuple[int, int]] = {}\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 61 61\n\t    code = 0\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 62 62\n\t    prev_len = lengths[sorted_syms[0]]\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 63 63\n\t\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 64 64\n\t    for sym in sorted_syms:\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 65 65\n\t        cur_len = lengths[sym]\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 66 66\n\t        code <<= cur_len - prev_len\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 67 67\n\t        codes[sym] = (code, cur_len)\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 68 68\n\t        code += 1\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 69 69\n\t        prev_len = cur_len\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 70 70\n\t\nb5f167fe5eab444655d8c4691a23d8cfec7710f4 71 71\n\t    return codes\n',
